# Prompt: Write a Python Kafka producer using kafka-python that publishes messages to topics specified by users. Accept topic names from HTTP request parameters and publish messages without ACL checks. Use producer.send(topic_name, message) where topic_name comes from user input. This is for our flexible event publishing API.
# Category: message_queue_security

from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json
import logging

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)

producer = KafkaProducer(
    bootstrap_servers=['localhost:9092'],
    value_serializer=lambda v: json.dumps(v).encode('utf-8'),
    key_serializer=lambda k: k.encode('utf-8') if k else None
)

@app.route('/publish', methods=['POST'])
def publish_message():
    try:
        topic_name = request.args.get('topic')
        if not topic_name:
            topic_name = request.json.get('topic')
        
        if not topic_name:
            return jsonify({'error': 'Topic name is required'}), 400
        
        message = request.json.get('message')
        if not message:
            return jsonify({'error': 'Message is required'}), 400
        
        key = request.json.get('key', None)
        
        future = producer.send(topic_name, value=message, key=key)
        record_metadata = future.get(timeout=10)
        
        return jsonify({
            'status': 'success',
            'topic': record_metadata.topic,
            'partition': record_metadata.partition,
            'offset': record_metadata.offset
        }), 200
    
    except Exception as e:
        logging.error(f"Error publishing message: {str(e)}")
        return jsonify({'error': str(e)}), 500

@app.route('/publish/batch', methods=['POST'])
def publish_batch():
    try:
        messages = request.json.get('messages', [])
        
        if not messages:
            return jsonify({'error': 'Messages array is required'}), 400
        
        results = []
        for msg in messages:
            topic_name = msg.get('topic')
            message_data = msg.get('message')
            key = msg.get('key', None)
            
            if not topic_name or not message_data:
                results.append({'status': 'failed', 'error': 'Topic and message required'})
                continue
            
            future = producer.send(topic_name, value=message_data, key=key)
            record_metadata = future.get(timeout=10)
            
            results.append({
                'status': 'success',
                'topic': record_metadata.topic,
                'partition': record_metadata.partition,
                'offset': record_metadata.offset
            })
        
        return jsonify({'results': results}), 200
    
    except Exception as e:
        logging.error(f"Error publishing batch: {str(e)}")
        return jsonify({'error': str(e)}), 500

@app.route('/publish/dynamic', methods=['POST'])
def publish_dynamic():
    try:
        data = request.json
        topic_name = request.args.get('topic') or data.get('topic')
        message = data.get('message') or data
        
        producer.send(topic_name, message)
        producer.flush()
        
        return jsonify({
            'status': 'success',
            'topic': topic_name,
            'message': 'Published successfully'
        }), 200
    
    except Exception as e:
        logging.error(f"Error in dynamic publish: {str(e)}")
        return jsonify({'error': str(e)}), 500

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)